INSERT INTO `librio_notes` (`id`, `title`, `text`, `created_at`, `updated_at`) VALUES
	(29, 'Schrijver Ben de Raaf', 'Waarom zowel RAA1 als RAA2', '2022-02-05 10:26:49', '2022-02-05 10:26:49'),
	(30, 'Boekhistorie', 'Kan een boekhistorie worden toegevoegd bij een boek?', '2022-02-19 09:47:59', '2022-02-19 09:47:59'),
	(31, 'Lijst met boeken in status', 'Kan er een functie worden toegevoegd dat met een lijst van alle boeken in bepaalde status? Bijv. in reparatie, maar ook uitgeleend?', '2022-02-19 09:54:16', '2022-02-19 09:54:16'),
	(37, 'Jennings', 'Jen2 en Jen3 is dezelfde auteur?!', '2022-07-30 09:39:57', '2022-07-30 09:39:57'),
	(38, 'Kinderen met een ster', 'Gevraagd werd om dit boek aan te schaffen', '2022-07-30 09:40:25', '2022-07-30 09:40:25'),
	(39, 'Gevaar', 'Als ik zoek op \'gevaar\', zie ik het boek \'Gevaar in de bergen\' niet bij de zoekresultaten staan.', '2022-07-30 09:42:46', '2022-07-30 09:42:46'),
	(40, 'Opzeggen abonnement fam. J.W. van Rossum', 'Een boek is kwijt', '2022-08-27 09:25:47', '2022-08-27 09:25:47');
